import{_ as a,o as i,c as t,a6 as s}from"./chunks/framework.DtxWasON.js";const m=JSON.parse('{"title":".und_mainchain/config/app.toml Reference","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/software/und-mainchain-app-config-ref.md","filePath":"mainchain/software/und-mainchain-app-config-ref.md"}'),n={name:"mainchain/software/und-mainchain-app-config-ref.md"};function l(p,e,o,h,r,d){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="und-mainchain-config-app-toml-reference" tabindex="-1"><code>.und_mainchain/config/app.toml</code> Reference <a class="header-anchor" href="#und-mainchain-config-app-toml-reference" aria-label="Permalink to &quot;`.und_mainchain/config/app.toml` Reference&quot;">​</a></h1><p>The <code>$HOME/.und_mainchain/config/app.toml</code> file contains all the configuration options for the <code>und</code> server binary. Below is a reference for the file.</p><h4 id="contents" tabindex="-1">Contents <a class="header-anchor" href="#contents" aria-label="Permalink to &quot;Contents&quot;">​</a></h4><nav class="table-of-contents"><ul><li><a href="#main-base-config-options">Main base config options</a><ul><li><a href="#minimum-gas-prices">minimum-gas-prices</a></li><li><a href="#pruning">pruning</a></li><li><a href="#halt-height">halt-height</a></li><li><a href="#halt-time">halt-time</a></li><li><a href="#min-retain-blocks">min-retain-blocks</a></li><li><a href="#inter-block-cache">inter-block-cache</a></li><li><a href="#index-events">index-events</a></li></ul></li><li><a href="#telemetry">telemetry</a><ul><li><a href="#telemetry-service-name">telemetry.service-name</a></li><li><a href="#telemetry-enabled">telemetry.enabled</a></li><li><a href="#telemetry-enable-hostname">telemetry.enable-hostname</a></li><li><a href="#telemetry-enable-hostname-label">telemetry.enable-hostname-label</a></li><li><a href="#telemetry-enable-service-label">telemetry.enable-service-label</a></li><li><a href="#telemetry-prometheus-retention-time">telemetry.prometheus-retention-time</a></li><li><a href="#telemetry-global-labels">telemetry.global-labels</a></li></ul></li><li><a href="#api">api</a><ul><li><a href="#api-enable">api.enable</a></li><li><a href="#api-swagger">api.swagger</a></li><li><a href="#api-address">api.address</a></li><li><a href="#api-max-open-connections">api.max-open-connections</a></li><li><a href="#api-rpc-read-timeout">api.rpc-read-timeout</a></li><li><a href="#api-rpc-write-timeout">api.rpc-write-timeout</a></li><li><a href="#api-rpc-max-body-bytes">api.rpc-max-body-bytes</a></li><li><a href="#api-enabled-unsafe-cors">api.enabled-unsafe-cors</a></li></ul></li><li><a href="#grpc">grpc</a><ul><li><a href="#grpc-enable">grpc.enable</a></li><li><a href="#grpc-address">grpc.address</a></li></ul></li><li><a href="#state-sync">state-sync</a><ul><li><a href="#state-sync-snapshot-interval">state-sync.snapshot-interval</a></li><li><a href="#state-sync-snapshot-keep-recent">state-sync.snapshot-keep-recent</a></li></ul></li></ul></nav><h2 id="main-base-config-options" tabindex="-1">Main base config options <a class="header-anchor" href="#main-base-config-options" aria-label="Permalink to &quot;Main base config options&quot;">​</a></h2><h3 id="minimum-gas-prices" tabindex="-1">minimum-gas-prices <a class="header-anchor" href="#minimum-gas-prices" aria-label="Permalink to &quot;minimum-gas-prices&quot;">​</a></h3><p>The minimum gas prices a validator is willing to accept for processing a transaction. A transaction&#39;s fees must meet the minimum of any denomination specified in this config (e.g. 25.0nund).</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">minimum-gas-prices = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;25.0nund&quot;</span></span></code></pre></div><h3 id="pruning" tabindex="-1">pruning <a class="header-anchor" href="#pruning" aria-label="Permalink to &quot;pruning&quot;">​</a></h3><p>default: the last 100 states are kept in addition to every 500th state; pruning at 10 block intervals nothing: all historic states will be saved, nothing will be deleted (i.e. archiving node) everything: all saved states will be deleted, storing only the current state; pruning at 10 block intervals custom: allow pruning options to be manually specified through &#39;pruning-keep-recent&#39;, &#39;pruning-keep-every&#39;, and &#39;pruning-interval&#39;</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pruning = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;default&quot;</span></span></code></pre></div><h4 id="pruning-keep-recent" tabindex="-1">pruning-keep-recent <a class="header-anchor" href="#pruning-keep-recent" aria-label="Permalink to &quot;pruning-keep-recent&quot;">​</a></h4><h4 id="pruning-keep-every" tabindex="-1">pruning-keep-every <a class="header-anchor" href="#pruning-keep-every" aria-label="Permalink to &quot;pruning-keep-every&quot;">​</a></h4><h4 id="pruning-interval" tabindex="-1">pruning-interval <a class="header-anchor" href="#pruning-interval" aria-label="Permalink to &quot;pruning-interval&quot;">​</a></h4><p>These are applied if and only if the pruning strategy is custom.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pruning-keep-recent = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;200&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pruning-keep-every = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1000&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pruning-interval = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;100&quot;</span></span></code></pre></div><h3 id="halt-height" tabindex="-1">halt-height <a class="header-anchor" href="#halt-height" aria-label="Permalink to &quot;halt-height&quot;">​</a></h3><p>HaltHeight contains a non-zero block height at which a node will gracefully halt and shutdown that can be used to assist upgrades and testing.</p><p>Note: Commitment of state will be attempted on the corresponding block.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">halt-height = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">123456789</span></span></code></pre></div><h3 id="halt-time" tabindex="-1">halt-time <a class="header-anchor" href="#halt-time" aria-label="Permalink to &quot;halt-time&quot;">​</a></h3><p>HaltTime contains a non-zero minimum block time (in Unix seconds) at which a node will gracefully halt and shutdown that can be used to assist upgrades and testing.</p><p>Note: Commitment of state will be attempted on the corresponding block.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">halt-time = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1654686000</span></span></code></pre></div><h3 id="min-retain-blocks" tabindex="-1">min-retain-blocks <a class="header-anchor" href="#min-retain-blocks" aria-label="Permalink to &quot;min-retain-blocks&quot;">​</a></h3><p>MinRetainBlocks defines the minimum block height offset from the current block being committed, such that all blocks past this offset are pruned from Tendermint. It is used as part of the process of determining the ResponseCommit.RetainHeight value during ABCI Commit. A value of 0 indicates that no blocks should be pruned.</p><p>This configuration value is only responsible for pruning Tendermint blocks. It has no bearing on application state pruning which is determined by the &quot;pruning-*&quot; configurations.</p><p>Note: Tendermint block pruning is dependant on this parameter in conunction with the unbonding (safety threshold) period, state pruning and state sync snapshot parameters to determine the correct minimum value of ResponseCommit.RetainHeight.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">min-retain-blocks = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span></code></pre></div><h3 id="inter-block-cache" tabindex="-1">inter-block-cache <a class="header-anchor" href="#inter-block-cache" aria-label="Permalink to &quot;inter-block-cache&quot;">​</a></h3><p>InterBlockCache enables inter-block caching.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">inter-block-cache = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><h3 id="index-events" tabindex="-1">index-events <a class="header-anchor" href="#index-events" aria-label="Permalink to &quot;index-events&quot;">​</a></h3><p>IndexEvents defines the set of events in the form {eventType}.{attributeKey}, which informs Tendermint what to index. If empty, all events will be indexed.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">index-events = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;message.sender&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;message.recipient&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><h2 id="telemetry" tabindex="-1">telemetry <a class="header-anchor" href="#telemetry" aria-label="Permalink to &quot;telemetry&quot;">​</a></h2><p>Configuration options in the <code>[telemetry]</code> section of the <code>app.toml</code> file.</p><h3 id="telemetry-service-name" tabindex="-1">telemetry.service-name <a class="header-anchor" href="#telemetry-service-name" aria-label="Permalink to &quot;telemetry.service-name&quot;">​</a></h3><p>Prefixed with keys to separate services.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">service-name = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span></span></code></pre></div><h3 id="telemetry-enabled" tabindex="-1">telemetry.enabled <a class="header-anchor" href="#telemetry-enabled" aria-label="Permalink to &quot;telemetry.enabled&quot;">​</a></h3><p>Enabled enables the application telemetry functionality. When enabled, an in-memory sink is also enabled by default. Operators may also enabled other sinks such as Prometheus.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enabled = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><h3 id="telemetry-enable-hostname" tabindex="-1">telemetry.enable-hostname <a class="header-anchor" href="#telemetry-enable-hostname" aria-label="Permalink to &quot;telemetry.enable-hostname&quot;">​</a></h3><p>Enable prefixing gauge values with hostname.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enable-hostname = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><h3 id="telemetry-enable-hostname-label" tabindex="-1">telemetry.enable-hostname-label <a class="header-anchor" href="#telemetry-enable-hostname-label" aria-label="Permalink to &quot;telemetry.enable-hostname-label&quot;">​</a></h3><p>Enable adding hostname to labels.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enable-hostname-label = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><h3 id="telemetry-enable-service-label" tabindex="-1">telemetry.enable-service-label <a class="header-anchor" href="#telemetry-enable-service-label" aria-label="Permalink to &quot;telemetry.enable-service-label&quot;">​</a></h3><p>Enable adding service to labels.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enable-service-label = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><h3 id="telemetry-prometheus-retention-time" tabindex="-1">telemetry.prometheus-retention-time <a class="header-anchor" href="#telemetry-prometheus-retention-time" aria-label="Permalink to &quot;telemetry.prometheus-retention-time&quot;">​</a></h3><p>PrometheusRetentionTime, when positive, enables a Prometheus metrics sink.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">prometheus-retention-time = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span></code></pre></div><h3 id="telemetry-global-labels" tabindex="-1">telemetry.global-labels <a class="header-anchor" href="#telemetry-global-labels" aria-label="Permalink to &quot;telemetry.global-labels&quot;">​</a></h3><p>GlobalLabels defines a global set of name/value label tuples applied to all metrics emitted using the wrapper functions defined in telemetry package.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">global-labels = [[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;chain_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;FUND-MainNet-2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]</span></span></code></pre></div><h2 id="api" tabindex="-1">api <a class="header-anchor" href="#api" aria-label="Permalink to &quot;api&quot;">​</a></h2><p>Configuration options in the <code>[api]</code> section of the <code>app.toml</code> file.</p><h3 id="api-enable" tabindex="-1">api.enable <a class="header-anchor" href="#api-enable" aria-label="Permalink to &quot;api.enable&quot;">​</a></h3><p>Enable defines if the API server should be enabled.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enable = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><h3 id="api-swagger" tabindex="-1">api.swagger <a class="header-anchor" href="#api-swagger" aria-label="Permalink to &quot;api.swagger&quot;">​</a></h3><p>Swagger defines if swagger documentation should automatically be registered.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">swagger = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><h3 id="api-address" tabindex="-1">api.address <a class="header-anchor" href="#api-address" aria-label="Permalink to &quot;api.address&quot;">​</a></h3><p>Address defines the API server to listen on.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">address = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tcp://0.0.0.0:1317&quot;</span></span></code></pre></div><h3 id="api-max-open-connections" tabindex="-1">api.max-open-connections <a class="header-anchor" href="#api-max-open-connections" aria-label="Permalink to &quot;api.max-open-connections&quot;">​</a></h3><p>MaxOpenConnections defines the number of maximum open connections.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">max-open-connections = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000</span></span></code></pre></div><h3 id="api-rpc-read-timeout" tabindex="-1">api.rpc-read-timeout <a class="header-anchor" href="#api-rpc-read-timeout" aria-label="Permalink to &quot;api.rpc-read-timeout&quot;">​</a></h3><p>RPCReadTimeout defines the Tendermint RPC read timeout (in seconds).</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rpc-read-timeout = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span></span></code></pre></div><h3 id="api-rpc-write-timeout" tabindex="-1">api.rpc-write-timeout <a class="header-anchor" href="#api-rpc-write-timeout" aria-label="Permalink to &quot;api.rpc-write-timeout&quot;">​</a></h3><p>RPCWriteTimeout defines the Tendermint RPC write timeout (in seconds).</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rpc-write-timeout = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span></code></pre></div><h3 id="api-rpc-max-body-bytes" tabindex="-1">api.rpc-max-body-bytes <a class="header-anchor" href="#api-rpc-max-body-bytes" aria-label="Permalink to &quot;api.rpc-max-body-bytes&quot;">​</a></h3><p>RPCMaxBodyBytes defines the Tendermint maximum response body (in bytes).</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rpc-max-body-bytes = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000000</span></span></code></pre></div><h3 id="api-enabled-unsafe-cors" tabindex="-1">api.enabled-unsafe-cors <a class="header-anchor" href="#api-enabled-unsafe-cors" aria-label="Permalink to &quot;api.enabled-unsafe-cors&quot;">​</a></h3><p>EnableUnsafeCORS defines if CORS should be enabled (unsafe - use it at your own risk).</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enabled-unsafe-cors = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><h2 id="grpc" tabindex="-1">grpc <a class="header-anchor" href="#grpc" aria-label="Permalink to &quot;grpc&quot;">​</a></h2><p>Configuration options in the <code>[grpc]</code> section of the <code>app.toml</code> file.</p><h3 id="grpc-enable" tabindex="-1">grpc.enable <a class="header-anchor" href="#grpc-enable" aria-label="Permalink to &quot;grpc.enable&quot;">​</a></h3><p>Enable defines if the gRPC server should be enabled.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enable = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><h3 id="grpc-address" tabindex="-1">grpc.address <a class="header-anchor" href="#grpc-address" aria-label="Permalink to &quot;grpc.address&quot;">​</a></h3><p>Address defines the gRPC server address to bind to.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">address = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.0.0.0:9090&quot;</span></span></code></pre></div><h2 id="state-sync" tabindex="-1">state-sync <a class="header-anchor" href="#state-sync" aria-label="Permalink to &quot;state-sync&quot;">​</a></h2><p>Configuration options in the <code>[state-sync]</code> section of the <code>app.toml</code> file.</p><p>State sync snapshots allow other nodes to rapidly join the network without replaying historical blocks, instead downloading and applying a snapshot of the application state at a given height.</p><h3 id="state-sync-snapshot-interval" tabindex="-1">state-sync.snapshot-interval <a class="header-anchor" href="#state-sync-snapshot-interval" aria-label="Permalink to &quot;state-sync.snapshot-interval&quot;">​</a></h3><p>snapshot-interval specifies the block interval at which local state sync snapshots are taken (0 to disable). Must be a multiple of pruning-keep-every.</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">snapshot-interval = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">500</span></span></code></pre></div><h3 id="state-sync-snapshot-keep-recent" tabindex="-1">state-sync.snapshot-keep-recent <a class="header-anchor" href="#state-sync-snapshot-keep-recent" aria-label="Permalink to &quot;state-sync.snapshot-keep-recent&quot;">​</a></h3><p>snapshot-keep-recent specifies the number of recent snapshots to keep and serve (0 to keep all).</p><p>Example</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">snapshot-keep-recent = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span></span></code></pre></div>',128)])])}const u=a(n,[["render",l]]);export{m as __pageData,u as default};
